export function getBlurDataUrl(imagePath: string): string | undefined {
  // Remove extension and normalize path
  const key = imagePath
    .replace(/^\/Images\/products(-avif)?\//, '')
    .replace(/\.avif$/, '')
    .replace(/\.(jpg|jpeg|png)$/i, '');
  
  return blurDataUrls[key];
}
